package basics;

public class SwitchCase {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a=2;
		
		switch(a)
		{
		case 1:
			System.out.println("JAN");
			break;
		case 2:
			System.out.println("FEB");
			break;
		case 3:
			System.out.println("MARCH");
			break;
		default:
			System.out.println("invalid choice");
			break;
		}

	}

}
